def run(self, items: List[Any]) -> Tuple[List[Any], List[Tuple[Any, Exception]]]:
    results = []
    errors = []
    for item in items:
        try:
            current = item
            for step in self.steps:
                current = step(current)
            results.append(current)
        except Exception as e:
            errors.append((item, e))
    return results, errors
